BaseWallet = class("BaseWallet")

function BaseWallet:ctor(wallet, rakssid)
    self.Wallet = wallet
    self.rakssid = rakssid
    self.MoneyCache = {}
end

function BaseWallet:destroy()
    self.Wallet = nil
    self.MoneyCache = {}
end

---设置自定义货币当前数量，可用于PayHelper检测货币是否足够
function BaseWallet:setMoneyCount(coinId, count)
    self.MoneyCache[coinId] = count
end

---通过货币类型获取货币数量，查询不到返回9999999999
function BaseWallet:getMoneyByCoinId(coinId)
    if coinId > 3 then
        return self.MoneyCache[coinId] or 9999999999
    end
    if not self.Wallet then
        return 0
    end
    return NumberUtil.int64ToNumber(self.Wallet:getMoneyByCoinId(coinId))
end

function BaseWallet:getGolds()
    if not self.Wallet then
        return 0
    end
    return NumberUtil.int64ToNumber(self.Wallet:getGolds())
end

function BaseWallet:getDiamondsBlues()
    if not self.Wallet then
        return 0
    end
    return NumberUtil.int64ToNumber(self.Wallet:getDiamondsBlues())
end

function BaseWallet:getDiamondsGolds()
    if not self.Wallet then
        return 0
    end
    return NumberUtil.int64ToNumber(self.Wallet:getDiamondsGolds())
end

function BaseWallet:getCurrency()
    if not self.Wallet then
        return 0
    end
    return NumberUtil.int64ToNumber(self.Wallet:getCurrency())
end

function BaseWallet:hasMoney(coinId, count)
    local nowCount = self:getMoneyByCoinId(coinId)
    if nowCount >= count then
        return true
    end
    return false
end